import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate, Toggle } from 'cc';
import { GameManager } from '../Core/GameManager';
import { QuestConfig } from '../Config/QuestConfig';

const { ccclass, property } = _decorator;

@ccclass('QuestScene')
export class QuestScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Toggle)
    mainTabToggle: Toggle = null;
    
    @property(Toggle)
    dailyTabToggle: Toggle = null;
    
    @property(Toggle)
    achievementTabToggle: Toggle = null;
    
    @property(ScrollView)
    questListScrollView: ScrollView = null;
    
    @property(Node)
    questItemPrefab: Node = null;
    
    private currentTab: string = 'main';
    
    private questProgress = {
        'main_001': { current: 1, target: 1, completed: true, claimed: true },
        'main_002': { current: 5, target: 1, completed: true, claimed: false },
        'main_003': { current: 3, target: 10, completed: false, claimed: false },
        'daily_001': { current: 2, target: 3, completed: false, claimed: false },
        'daily_002': { current: 0, target: 5, completed: false, claimed: false }
    };
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.mainTabToggle.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('main'), this);
        this.dailyTabToggle.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('daily'), this);
        this.achievementTabToggle.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('achievement'), this);
    }
    
    start() {
        this.updateQuestList();
    }
    
    onTabChange(tab: string) {
        this.currentTab = tab;
        this.updateQuestList();
    }
    
    updateQuestList() {
        const content = this.questListScrollView.content;
        content.removeAllChildren();
        
        let quests = [];
        if (this.currentTab === 'main') {
            quests = QuestConfig.mainQuests;
        } else if (this.currentTab === 'daily') {
            quests = QuestConfig.dailyQuests;
        } else {
            quests = QuestConfig.achievements;
        }
        
        for (const quest of quests) {
            const progress = this.questProgress[quest.id] || { current: 0, target: 1, completed: false, claimed: false };
            
            const item = instantiate(this.questItemPrefab);
            
            item.getChildByName('NameLabel').getComponent(Label).string = quest.name;
            item.getChildByName('DescLabel').getComponent(Label).string = quest.desc;
            item.getChildByName('ProgressLabel').getComponent(Label).string = 
                `${progress.current}/${progress.target}`;
            
            // 奖励显示
            let rewardText = '';
            for (const [key, value] of Object.entries(quest.reward)) {
                rewardText += `${key}:${value} `;
            }
            item.getChildByName('RewardLabel').getComponent(Label).string = rewardText;
            
            // 状态按钮
            const claimBtn = item.getChildByName('ClaimBtn').getComponent(Button);
            const claimLabel = claimBtn.getComponent(Label);
            
            if (progress.claimed) {
                claimLabel.string = '已完成';
                claimBtn.interactable = false;
            } else if (progress.completed) {
                claimLabel.string = '领取';
                claimBtn.interactable = true;
                claimBtn.node.on(Button.EventType.CLICK, () => this.onClaim(quest), this);
            } else {
                claimLabel.string = '进行中';
                claimBtn.interactable = false;
            }
            
            content.addChild(item);
        }
    }
    
    onClaim(quest: any) {
        const progress = this.questProgress[quest.id];
        if (!progress || !progress.completed || progress.claimed) return;
        
        // 发放奖励
        for (const [key, value] of Object.entries(quest.reward)) {
            GameManager.getInstance().playerData.addCurrency(key, value as number);
        }
        
        progress.claimed = true;
        this.updateQuestList();
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
